class Solution:
    def firstUniqueFreq(self, nums):
        freq = {}
        for v in nums:
            freq[v] = freq.get(v, 0) + 1
        for v in nums:
            f = freq[v]
            shared = sum(1 for other in freq.values() if other == f)
            if shared == 1:
                return v
        return -1

