from collections import Counter

class Solution:
    def firstUniqueFreq(self, nums: 'list[int]') -> int:
        counts = Counter(nums)
        freq_of_freq = Counter(counts.values())
        for v in nums:
            if freq_of_freq[counts[v]] == 1:
                return v
        return -1

